import { Component } from '@angular/core';
import { finalize } from 'rxjs';
import { FormControl, FormGroup, Validators,FormsModule } from '@angular/forms';
import { HttpService } from '../http.service';
import { Router } from '@angular/router';
import { Contacts } from './contacts.interface';

@Component({
  selector: 'app-contacts',
  templateUrl: './contacts.component.html',
  styleUrls: ['./contacts.component.scss']
})
export class ContactsComponent {
  data: Contacts[] = [];
  Form?: FormGroup;
  isSended= false;


  buildForm(item?: Contacts) {
    this.Form = new FormGroup({
        firstName: new FormControl('',[
            Validators.required,
        ]),
        lastName: new FormControl('',[
            Validators.required,
        ]),
        email: new FormControl('',[
            Validators.required,
        ]),
        phone: new FormControl('',[
          Validators.required,
        ]),
        address: new FormControl('',[
        Validators.required,
    ]),
    });
}



  addContact(){
    const sub = this.http.post<Contacts[]>("customer", this.Form?.value).pipe(finalize(() => {
        if (sub?.unsubscribe) {
            sub.unsubscribe();
        }
    })).subscribe(data => {
        this.isSended = true;
        this.router.navigate(['/customers']);

    });
  }



  delete(){

  }


     constructor (private router: Router,private http: HttpService ) {

     }

}
<p>contacts works!</p>

<h4>אנשי קשר</h4>
<button class="w3-btn w3-green w3-round w3-block" routerLink="/contacts" (click)="addContact" >איש קשר חדש<i class="fa far fa-plus-square"></i></button>

<table class="w3-table w3-striped w3-bordered">
    <thead>
        <tr>
            <th>שם פרטי</th>
            <th>שם משפחה</th>
            <th>טלפון</th>
            <th>אימייל</th>
            <th>  </th>
        </tr>
    </thead>
    <tbody>
        <tr *ngFor="let item of data">
            <td>{{ item.firsName }}</td>
            <td>{{ item.lastName }}</td>
            <td>{{ item.phone }}</td>
            <td>{{ item.email }}</td>
            <td><button class="w3-btn w3-green w3-round"><i class="fa fa-edit" [routerLink]="['/','contacts', item.id]"></i></button></td>
            <td><button class="w3-btn w3-red w3-round" (click)="delete()">x</button></td>

        </tr>
    </tbody>
</table>
